// ===== TABS DO CARDÁPIO =====
function showTab(id, btn) {
  document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  document.getElementById('tab-' + id).classList.add('active');
  if (btn) {
    btn.classList.add('active');
  } else {
    document.querySelectorAll('.tab').forEach(t => {
      if (t.textContent.toLowerCase().includes(id)) t.classList.add('active');
    });
  }
  if (typeof gtag !== 'undefined') {
    gtag('event', 'click_tab_cardapio', {event_category: 'cardapio', event_label: id});
  }
}

// ===== CARROSSEL DE PRODUTOS =====
function initCarousels() {
  var rem = parseFloat(getComputedStyle(document.documentElement).fontSize) || 16;
  var sectionPad = window.innerWidth <= 768 ? 2 * rem : 8 * rem;
  var pageW = window.innerWidth - sectionPad;
  var carW = pageW;
  var defaultVisible = window.innerWidth >= 500 ? 2 : 1;
  ['bolos', 'doces', 'personalizados'].forEach(function(id) {
    var outer = document.getElementById('carousel-' + id);
    if (!outer) return;
    var visibleCount = (window.innerWidth >= 768 && outer.dataset.visible)
      ? parseInt(outer.dataset.visible) : defaultVisible;
    var cardW = Math.floor((carW - (visibleCount - 1) * 14) / visibleCount);
    var cards = outer.querySelectorAll('.carousel-card');
    cards.forEach(function(card) {
      card.style.width = cardW + 'px';
      var foto = card.querySelector('.carousel-foto');
      var img = foto && foto.querySelector('img');
      if (img && img.src) {
        var defaultBgSize = outer.dataset.bgSize || 'cover';
        foto.style.backgroundImage = 'url("' + img.src + '")';
        foto.style.backgroundSize = foto.dataset.size || defaultBgSize;
        foto.style.backgroundPosition = foto.dataset.position || 'center center';
        foto.style.backgroundRepeat = 'no-repeat';
        img.style.display = 'none';
        if (!foto.dataset.lbBound) {
          foto.dataset.lbBound = '1';
          (function(cardEl, outerEl) {
            foto.addEventListener('click', function() {
              var allCards = Array.from(outerEl.querySelectorAll('.carousel-card'));
              var images = allCards.map(function(c) {
                var f = c.querySelector('.carousel-foto');
                var im = f && f.querySelector('img');
                var n = (c.querySelector('.produto-nome') || {}).textContent || '';
                return im && im.src ? { src: im.src, name: n.trim() } : null;
              }).filter(Boolean);
              var idx = allCards.indexOf(cardEl);
              openLightbox(images, Math.max(0, idx));
            });
          })(card, outer);
        }
      }
    });
  });
}
window.addEventListener('load', function() { setTimeout(initCarousels, 50); });
window.addEventListener('resize', initCarousels);

// ===== LIGHTBOX =====
var _lbImages = [], _lbIdx = 0;

function openLightbox(images, idx) {
  _lbImages = images;
  _lbIdx = idx || 0;
  _lbRender();
  document.getElementById('lightbox').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function _lbRender() {
  var item = _lbImages[_lbIdx];
  if (!item) return;
  document.getElementById('lightbox-img').src = item.src;
  document.getElementById('lightbox-img').alt = item.name;
  document.getElementById('lightbox-label').textContent = item.name;
  var prev = document.getElementById('lb-prev');
  var next = document.getElementById('lb-next');
  if (prev && next) {
    var show = _lbImages.length > 1;
    prev.style.display = show ? 'flex' : 'none';
    next.style.display = show ? 'flex' : 'none';
    prev.disabled = _lbIdx <= 0;
    next.disabled = _lbIdx >= _lbImages.length - 1;
  }
}

function lbNavigate(dir) {
  _lbIdx = Math.max(0, Math.min(_lbImages.length - 1, _lbIdx + dir));
  _lbRender();
}

function closeLightbox(e) {
  if (e && (e.target.tagName === 'IMG' || e.target.id === 'lb-prev' || e.target.id === 'lb-next')) return;
  document.getElementById('lightbox').classList.remove('open');
  document.body.style.overflow = '';
  setTimeout(function() {
    var img = document.getElementById('lightbox-img');
    if (img) img.src = '';
  }, 300);
}

document.addEventListener('keydown', function(e) {
  if (!document.getElementById('lightbox').classList.contains('open')) return;
  if (e.key === 'Escape') closeLightbox();
  if (e.key === 'ArrowLeft') lbNavigate(-1);
  if (e.key === 'ArrowRight') lbNavigate(1);
});

var _carPos = {};
function moveCarousel(id, dir) {
  var track = document.querySelector('#carousel-' + id + ' .carousel-track');
  if (!track) return;
  var outer = document.getElementById('carousel-' + id);
  var cards = track.querySelectorAll('.carousel-card');
  var visible = window.innerWidth < 500 ? 1
    : (window.innerWidth >= 768 && outer && outer.dataset.visible ? parseInt(outer.dataset.visible) : 2);
  var max = Math.max(0, cards.length - visible);
  _carPos[id] = Math.max(0, Math.min(max, (_carPos[id] || 0) + dir));
  var gap = 14;
  var cardW = cards[0].offsetWidth + gap;
  track.style.transform = 'translateX(-' + (_carPos[id] * cardW) + 'px)';
  var wrap = document.getElementById('carousel-' + id);
  wrap.querySelector('.carousel-prev').disabled = _carPos[id] <= 0;
  wrap.querySelector('.carousel-next').disabled = _carPos[id] >= max;
}

// ===== NAV ATIVO NO SCROLL =====
window.addEventListener('scroll', () => {
  const sections = ['missao', 'cardapio', 'momentos', 'orcamento'];
  const links = document.querySelectorAll('.nav-links a');
  sections.forEach((id, i) => {
    const el = document.getElementById(id);
    if (!el) return;
    const rect = el.getBoundingClientRect();
    if (rect.top <= 100 && rect.bottom >= 100) {
      links.forEach(l => l.classList.remove('active'));
      if (links[i]) links[i].classList.add('active');
    }
  });
});

// ===== FORMULÁRIO → WHATSAPP =====
function enviarOrcamento() {
  const nome       = (document.getElementById('nome')       ||{}).value||'';
  const whatsapp   = (document.getElementById('whatsapp')   ||{}).value||'';
  const evento     = (document.getElementById('evento')     ||{}).value||'';
  const data       = (document.getElementById('data')       ||{}).value||'';
  const convidados = (document.getElementById('convidados') ||{}).value||'';
  const produto    = (document.getElementById('produto')    ||{}).value||'';
  var lgpdCheck = document.getElementById('lgpd-check');
  if (lgpdCheck && !lgpdCheck.checked) { alert('Por favor, aceite a Política de Privacidade para continuar.'); return; }
  if (!nome.trim()) { alert('Por favor, preencha seu nome.'); return; }
  let msg = 'Olá! Gostaria de solicitar um orçamento.\n\n';
  msg += '*Nome:* ' + nome.trim() + '\n';
  if (whatsapp.trim())   msg += '*WhatsApp:* ' + whatsapp.trim() + '\n';
  if (evento)            msg += '*Evento:* ' + evento + '\n';
  if (data)              msg += '*Data:* ' + data + '\n';
  if (convidados.trim()) msg += '*Convidados:* ' + convidados.trim() + '\n';
  if (produto)           msg += '*Produto:* ' + produto + '\n';
  if (typeof gtag !== 'undefined') {
    gtag('event', 'lead', {event_category: 'orcamento', event_label: evento || 'sem_evento'});
  }
  window.open('https://wa.me/5511961739148?text=' + encodeURIComponent(msg), '_blank');
}

