var _galeriaEventos = {
  casamentos:   ['imagens/2.jpg','imagens/13.jpg','imagens/14.jpg','imagens/casamentos.jpg','imagens/casamentos-2.jpg','imagens/casamentos-3.jpg','imagens/casamentos-4.jpg'],
  aniversarios: ['imagens/17.jpg','imagens/aniversarios.jpg','imagens/aniversario-2.jpg','imagens/aniversarios-3.jpg','imagens/aniversarios-4.jpg','imagens/aniversarios-5.jpg','imagens/aniversarios-6.jpg'],
  formaturas:   ['imagens/10.jpg','imagens/formaturas.jpg','imagens/formaturas-2.jpg','imagens/formaturas-3.jpg'],
  chabebe:      ['imagens/11.jpg','imagens/cha-bebe.jpg','imagens/cha-bebe-2.jpg','imagens/cha-bebe-3.jpg','imagens/cha-bebe-4.jpg','imagens/cha-bebe-5.jpg'],
  corporativo:  ['imagens/12.jpg','imagens/8.jpg','imagens/9.jpg','imagens/7.jpg','imagens/1.jpg','imagens/3.jpg','imagens/4.jpg','imagens/5.jpg','imagens/6.jpg','imagens/corporativo.jpg','imagens/corporativo-2.jpg','imagens/corporativo-3.jpg','imagens/corporativo-4.jpg'],
  festas:       ['imagens/18.jpg','imagens/15.jpg','imagens/16.jpg','imagens/festas.jpg','imagens/festas-2.jpg','imagens/festas-3.jpg','imagens/festas-4.jpg','imagens/festas-5.jpg','imagens/festas-6.jpg','imagens/festas-7.jpg','imagens/festas-8.jpg']
};

function initLightboxEventos() {
  if (document.getElementById('lb-modal')) return; // evita double init
  // Criar modal
  var modal = document.createElement('div');
  modal.id = 'lb-modal';
  modal.innerHTML =
    '<div id="lb-overlay"></div>'+
    '<div id="lb-box">'+
      '<button id="lb-close" aria-label="Fechar">&#10005;</button>'+
      '<button id="lb-prev" aria-label="Anterior">&#8249;</button>'+
      '<img id="lb-img" src="" alt="">'+
      '<button id="lb-next" aria-label="Próxima">&#8250;</button>'+
      '<div id="lb-counter"></div>'+
    '</div>';
  document.body.appendChild(modal);

  var imgs=[], cur=0;

  function abrir(lista, idx) {
    imgs=lista; cur=idx;
    mostrar();
    modal.classList.add('ativo');
    document.body.style.overflow='hidden';
  }
  function fechar() {
    modal.classList.remove('ativo');
    document.body.style.overflow='';
  }
  function mostrar() {
    document.getElementById('lb-img').src=imgs[cur];
    document.getElementById('lb-counter').textContent=(cur+1)+' / '+imgs.length;
    document.getElementById('lb-prev').style.display=imgs.length>1?'flex':'none';
    document.getElementById('lb-next').style.display=imgs.length>1?'flex':'none';
  }
  function prev() { cur=(cur-1+imgs.length)%imgs.length; mostrar(); }
  function next() { cur=(cur+1)%imgs.length; mostrar(); }

  document.getElementById('lb-close').onclick=fechar;
  document.getElementById('lb-overlay').onclick=fechar;
  document.getElementById('lb-prev').onclick=prev;
  document.getElementById('lb-next').onclick=next;

  document.addEventListener('keydown',function(e){
    if(!modal.classList.contains('ativo')) return;
    if(e.key==='Escape') fechar();
    if(e.key==='ArrowLeft') prev();
    if(e.key==='ArrowRight') next();
  });

  // Swipe mobile
  var tx=0;
  document.getElementById('lb-box').addEventListener('touchstart',function(e){ tx=e.touches[0].clientX; });
  document.getElementById('lb-box').addEventListener('touchend',function(e){
    var dx=e.changedTouches[0].clientX-tx;
    if(Math.abs(dx)>50){ dx<0?next():prev(); }
  });

  // Ligar cards aos eventos
  var chaves=['casamentos','aniversarios','formaturas','chabebe','corporativo','festas'];
  document.querySelectorAll('.evento-card').forEach(function(card,i){
    var img=card.querySelector('.evento-img');
    if(img && _galeriaEventos[chaves[i]]) {
      img.style.cursor='zoom-in';
      img.addEventListener('click',function(e){
        e.stopPropagation();
        abrir(_galeriaEventos[chaves[i]], 0);
      });
    }
  });
}
document.addEventListener('DOMContentLoaded', initLightboxEventos);
if(document.readyState!=='loading') initLightboxEventos();

// ===== MENU MOBILE =====

function fecharMenu() {
  var btn = document.getElementById('nav-hamburger');
  var drawer = document.getElementById('mobile-nav-drawer');
  var overlay = document.getElementById('mobile-nav-overlay');
  if (btn) { btn.classList.remove('ativo'); btn.setAttribute('aria-expanded','false'); }
  if (drawer) drawer.classList.remove('ativo');
  if (overlay) overlay.classList.remove('ativo');
  document.body.style.overflow = '';
}

(function() {
  var btn = document.getElementById('nav-hamburger');
  var drawer = document.getElementById('mobile-nav-drawer');
  var overlay = document.getElementById('mobile-nav-overlay');
  if (!btn) return;
  btn.addEventListener('click', function() {
    var aberto = drawer.classList.contains('ativo');
    if (aberto) {
      fecharMenu();
    } else {
      btn.classList.add('ativo');
      btn.setAttribute('aria-expanded','true');
      drawer.classList.add('ativo');
      overlay.classList.add('ativo');
      document.body.style.overflow = 'hidden';
    }
  });
  if (overlay) overlay.addEventListener('click', fecharMenu);
})();

